(function(){
  function noop() {}

  function trigger(inst, eventName, args) {
    var handlers = inst._handlers[eventName] || [];
    for (var i = 0; i < handlers.length; i++) {
      handlers[i].apply(inst, args || []);
    }
  }

  function createHiddenInput(inst) {
    var input = document.createElement('input');
    input.type = 'file';
    input.multiple = true;
    input.style.display = 'none';
    input.addEventListener('change', function() {
      if (input.files && input.files.length) {
        for (var i = 0; i < input.files.length; i++) {
          inst._queue.push(input.files[i]);
        }
      }
      input.value = '';
    });
    return input;
  }

  function getXHRError(xhr) {
    if (!xhr) {
      return 'Upload failed';
    }
    if (xhr.responseText) {
      return xhr.responseText;
    }
    return 'HTTP ' + xhr.status;
  }

  function sendFile(inst, file, done) {
    var xhr = new XMLHttpRequest();
    var formData = new FormData();
    var paramName = inst.options.paramName || 'file';

    file.upload = file.upload || {};
    if (!file.upload.uuid) {
      file.upload.uuid = 'xxxxxxxxxxxx4xxxyxxxxxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
        var r = Math.random() * 16 | 0;
        var v = c === 'x' ? r : (r & 0x3 | 0x8);
        return v.toString(16);
      });
    }

    formData.append(paramName, file, file.name);
    trigger(inst, 'sending', [file, xhr, formData]);

    xhr.onreadystatechange = function() {
      if (xhr.readyState !== 4) {
        return;
      }
      if (xhr.status >= 200 && xhr.status < 300) {
        trigger(inst, 'success', [file, xhr.responseText, xhr]);
      } else {
        trigger(inst, 'error', [file, getXHRError(xhr), xhr]);
      }
      done();
    };

    xhr.open('POST', inst.options.url || inst.element.getAttribute('action') || window.location.href, true);
    xhr.send(formData);
  }

  function processNext(inst) {
    if (inst._active >= inst.options.parallelUploads || inst._queue.length === 0) {
      if (inst._active === 0 && inst._queue.length === 0) {
        trigger(inst, 'queuecomplete', []);
      }
      return;
    }

    var file = inst._queue.shift();
    inst._active++;
    sendFile(inst, file, function() {
      inst._active--;
      processNext(inst);
      if (inst._queue.length > 0 && inst._active < inst.options.parallelUploads) {
        processNext(inst);
      }
    });

    if (inst._active < inst.options.parallelUploads && inst._queue.length > 0) {
      processNext(inst);
    }
  }

  function setupDragDrop(inst) {
    function prevent(e) {
      e.preventDefault();
      e.stopPropagation();
    }

    inst.element.addEventListener('dragover', prevent);
    inst.element.addEventListener('dragenter', prevent);
    inst.element.addEventListener('drop', function(e) {
      prevent(e);
      var files = (e.dataTransfer && e.dataTransfer.files) ? e.dataTransfer.files : [];
      for (var i = 0; i < files.length; i++) {
        inst._queue.push(files[i]);
      }
      if (inst.options.autoProcessQueue !== false) {
        inst.processQueue();
      }
    });

    inst.element.addEventListener('click', function() {
      inst._input.click();
    });
  }

  function Dropzone(selector, options) {
    if (!(this instanceof Dropzone)) {
      return new Dropzone(selector, options);
    }

    this.element = typeof selector === 'string' ? document.querySelector(selector) : selector;
    if (!this.element) {
      throw new Error('Dropzone element not found: ' + selector);
    }

    this.options = options || {};
    if (typeof this.options.parallelUploads !== 'number' || this.options.parallelUploads < 1) {
      this.options.parallelUploads = 1;
    }

    this._handlers = {};
    this._queue = [];
    this._active = 0;

    this._input = createHiddenInput(this);
    this.element.appendChild(this._input);

    var self = this;
    this._input.addEventListener('change', function() {
      if (self.options.autoProcessQueue !== false) {
        self.processQueue();
      }
    });

    setupDragDrop(this);
  }

  Dropzone.prototype.on = function(eventName, handler) {
    if (!this._handlers[eventName]) {
      this._handlers[eventName] = [];
    }
    this._handlers[eventName].push(typeof handler === 'function' ? handler : noop);
    return this;
  };

  Dropzone.prototype.getQueuedFiles = function() {
    return this._queue.slice();
  };

  Dropzone.prototype.processQueue = function() {
    processNext(this);
  };

  Dropzone.autoDiscover = false;
  window.Dropzone = Dropzone;
})();
